<template>
  <AppLayout :breadcrumbs="['首页', '用户管理']">
    <!--搜索与功能-->
    <div style="margin-bottom: 20px; display: flex; align-items: center; gap: 8px">
      <a-input
          v-model="input"
          :style="{ width: '260px' }"
          placeholder="请输入用户ID"
          allow-clear
      />
      <a-button @click="getByUid" type="primary" status="success">搜索</a-button>
      <a-button type="primary" status="warning" style="margin-left: 14px" @click="showAddUserModal">新增用户</a-button>
      <a-button type="primary" @click="getAllUsers">查询全部</a-button>
    </div>
    <!--内容-->
    <a-table :columns="columns" :data="Listdata" :pagination="pagination">
      <template #optional="{ record }">
        <a-button @click="showEditUserModal(record)" status="warning">编辑</a-button>
        <a-button status="danger" style="margin-left: 10px;" @click="getDeleteUser(record.uid)">删除</a-button>
      </template>
    </a-table>

    <!-- 新增用户弹框 -->
    <a-modal v-model:visible="addUserModalVisible" title="新增用户" @cancel="handleCancelAddUser" @ok="handleSubmitAddUser">
      <a-form :model="addUserForm" :rules="rules" ref="addUserFormRef">
        <a-form-item field="uid" label="用户ID">
          <a-input v-model="addUserForm.uid" allow-clear/>
        </a-form-item>
        <a-form-item field="userName" label="用户名">
          <a-input v-model="addUserForm.userName" allow-clear />
        </a-form-item>
        <a-form-item field="realName" label="真实名">
          <a-input v-model="addUserForm.realName" allow-clear />
        </a-form-item>
        <a-form-item field="passWord" label="密码">
          <a-input-password
              v-model="addUserForm.passWord"
              v-model:visibility="addPwdVisible"
              :defaultVisibility="false"
              allow-clear
          />
        </a-form-item>
        <a-form-item field="uaddress" label="地址">
          <a-input v-model="addUserForm.uaddress" allow-clear />
        </a-form-item>
        <a-form-item field="uphone" label="电话">
          <a-input v-model="addUserForm.uphone" allow-clear />
        </a-form-item>
      </a-form>
    </a-modal>

    <!-- 编辑用户弹框 -->
    <a-modal v-model:visible="editUserModalVisible" title="编辑用户" @cancel="handleCancelEditUser" @ok="handleSubmitEditUser">
      <a-form :model="editUserForm" :rules="rules" ref="editUserFormRef">
        <a-form-item field="uid" label="用户ID">
          <a-input v-model="editUserForm.uid" allow-clear disabled/>
        </a-form-item>
        <a-form-item field="userName" label="用户名">
          <a-input v-model="editUserForm.userName" allow-clear />
        </a-form-item>
        <a-form-item field="realName" label="真实名">
          <a-input v-model="editUserForm.realName" allow-clear />
        </a-form-item>
        <a-form-item field="passWord" label="密码">
          <a-input-password
              v-model="editUserForm.passWord"
              v-model:visibility="editPwdVisible"
              :defaultVisibility="false"
              allow-clear
          />
        </a-form-item>
        <a-form-item field="uaddress" label="地址">
          <a-input v-model="editUserForm.uaddress" allow-clear />
        </a-form-item>
        <a-form-item field="uphone" label="电话">
          <a-input v-model="editUserForm.uphone" allow-clear />
        </a-form-item>
      </a-form>
    </a-modal>
  </AppLayout>
</template>

<script>
import {loadUsers, getUserById, addUser, updateUser, deleteUser} from "@/api/UserRequst";
import {defineComponent} from 'vue';
import {Message} from '@arco-design/web-vue';
import AppLayout from "@/components/AppLayout.vue";

export default defineComponent({
  name: "users",
  components: {AppLayout},
  // 数据
  data() {
    return {
      Listdata: [],
      input: "",
      addUserModalVisible: false,
      editUserModalVisible: false,
      addUserForm: {
        uid:'',
        userName: '',
        realName: '',
        passWord: '',
        uaddress: '',
        uphone: ''
      },
      editUserForm: {
        uid:'',
        userName: '',
        realName: '',
        passWord: '',
        uaddress: '',
        uphone: ''
      },
      visibility: true,
      addPwdVisible: false,
      editPwdVisible: false,
      rules: {
        uid: [
          { required: true, message: '请输入用户ID', trigger: 'blur' },
          { pattern: /^[0-9]+$/, message: '用户ID必须为数字', trigger: 'blur' }
        ],
        userName: [
          { required: true, message: '请输入用户名', trigger: 'blur' },
          { min: 3, max: 20, message: '用户名长度为3-20个字符', trigger: 'blur' }
        ],
        realName: [
          { required: true, message: '请输入真实名', trigger: 'blur' },
          { min: 2, max: 20, message: '真实名长度为2-20个字符', trigger: 'blur' }
        ],
        passWord: [
          { required: true, message: '请输入密码', trigger: 'blur' },
          { min: 6, max: 20, message: '密码长度为6-20个字符', trigger: 'blur' }
        ],
        uaddress: [
          { required: true, message: '请输入地址', trigger: 'blur' },
          { min: 5, max: 50, message: '地址长度为5-50个字符', trigger: 'blur' }
        ],
        uphone: [
          { required: true, message: '请输入电话', trigger: 'blur' },
          { pattern: /^[0-9]+$/, message: '电话必须为数字', trigger: 'blur' }
        ]
      },
      columns: [
        {
          title: 'ID',
          dataIndex: 'uid'
        },
        {
          title: '用户名',
          dataIndex: 'userName'
        },
        {
          title: '真实名',
          dataIndex: 'realName'
        },
        {
          title: '地址',
          dataIndex: 'uaddress'
        },
        {
          title: '电话',
          dataIndex: 'uphone'
        },
        {
          title: '操作',
          slotName: 'optional'
        }
      ],
      pagination: {
        showTotal: true,
        showJumper: true,
        sizeCanChange: true,
        pageSize: 8,
        pageSizeChange: (pageSize) => {
          this.pagination.pageSize = pageSize;
          this.getLoad();
        },
        currentChange: (current) => {
          this.pagination.currentPage = current;
          this.getLoad();
        }
      },
    };
  },
  methods: {
    // 加载用户信息
    getLoad() {
      loadUsers().then(res => {
        this.Listdata = res.data.data;
      }).catch(() => {
        Message.error("加载用户失败");
      });
    },
    // 根据uid查询用户信息
    getByUid() {
      getUserById(this.input).then(res => {
        this.Listdata = res.data.data;
      }).catch(() => {
        Message.error("请规范输入数字ID");
      });
    },
    // 查询全部用户信息
    getAllUsers() {
      this.getLoad();
    },
    // 删除用户
    getDeleteUser(uid) {
      deleteUser(uid).then(() => {
        this.getLoad();
        Message.success({content: '用户删除成功', showIcon: true});
      }).catch(() => {
        Message.error("删除失败");
      });
    },
    // 显示新增用户弹框
    showAddUserModal() {
      this.resetForm('add');
      this.addUserModalVisible = true;
    },
    // 关闭新增用户弹框
    handleCancelAddUser() {
      this.addUserModalVisible = false;
    },
    // 提交新增用户信息
    handleSubmitAddUser() {
      this.$refs.addUserFormRef.validate().then(() => {
        this.submitAddUser();
      }).catch(() => {
        Message.error({content: '请检查输入内容', showIcon: true});
      });
    },
    // 新增用户
    submitAddUser() {
      addUser(this.addUserForm).then(() => {
        this.getLoad();
        Message.success({content: '用户新增成功', showIcon: true});
        this.handleCancelAddUser();
      }).catch(() => {
        Message.error({content: '用户新增失败', showIcon: false});
      });
    },
    // 显示编辑用户弹框
    showEditUserModal(record) {
      this.editUserForm = {...record};
      this.editUserModalVisible = true;
    },
    // 关闭编辑用户弹框
    handleCancelEditUser() {
      this.editUserModalVisible = false;
    },
    // 提交编辑用户信息
    handleSubmitEditUser() {
      this.$refs.editUserFormRef.validate().then(() => {
        this.submitUpdateUser();
      }).catch(() => {
        Message.error({content: '请检查输入内容', showIcon: true});
      });
    },
    // 更新用户信息
    submitUpdateUser() {
      updateUser(this.editUserForm).then(() => {
        this.getLoad();
        Message.success({content: '用户信息更新成功', showIcon: true});
        this.handleCancelEditUser();
      }).catch(() => {
        Message.error("更新用户失败");
      });
    },
    // 重置表单
    resetForm(formType) {
      if (formType === 'add') {
        this.addUserForm = {
          uid: '',
          userName: '',
          realName: '',
          passWord: '',
          uaddress: '',
          uphone: ''
        };
      } else if (formType === 'edit') {
        this.editUserForm = {
          uid: '',
          userName: '',
          realName: '',
          passWord: '',
          uaddress: '',
          uphone: ''
        };
      }
    }
  },
  mounted() {
    this.getLoad(); // 组件挂载后加载用户列表
  }
});
</script>

